DROP TABLE IF EXISTS games;
CREATE TABLE games (id INT AUTO_INCREMENT PRIMARY KEY, date BIGINT, size INT, player_white VARCHAR(20), player_black VARCHAR(20), notation TEXT, result VARCHAR(10), timertime INT DEFAULT 0, timerinc INT DEFAULT 0, rating_white int default 1000, rating_black int default 1000, unrated int default 0, tournament int default 0, komi int default 0, pieces int default -1, capstones int default -1, rating_change_white int default 0, rating_change_black int default 0, extra_time_amount int DEFAULT 0, extra_time_trigger int DEFAULT 0, created_at TIMESTAMP default CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted_at TIMESTAMP NULL DEFAULT NULL);

DROP TABLE IF EXISTS players;
CREATE TABLE players (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(20) NOT NULL, password VARCHAR(150) NOT NULL, email VARCHAR(50) NOT NULL, r4 INT, r5 INT,r6 INT, r7 INT,r8 INT, rating real default 1000, boost real default 750, ratedgames int default 0, maxrating real default 1000, ratingage real default 0, ratingbase int default 0, unrated int default 0, isbot int default 0, fatigue text default '{}', is_admin int DEFAULT 0, is_mod int DEFAULT 0, is_gagged INT DEFAULT 0, is_banned INT DEFAULT 0, participation_rating real DEFAULT 0, last_logged_in_at TIMESTAMP NULL DEFAULT NULL, created_at TIMESTAMP default CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted_at TIMESTAMP NULL DEFAULT NULL);